// Compute resume time: tomorrow at 9am CT (UTC-5 CST / UTC-6 CDT)
const now = new Date();
const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);
tomorrow.setUTCHours(15, 0, 0, 0);

const body = $('Receive Sign-In').first().json.body;

// Required field validation
const required = ['attendee_name', 'phone', 'agent_name', 'agent_email', 'agent_phone', 'property_address'];
for (const field of required) {
  if (!body[field] || !String(body[field]).trim()) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Length caps
const maxLengths = { attendee_name: 100, brought_you_in: 500, property_notes: 1000 };
for (const [field, max] of Object.entries(maxLengths)) {
  if (body[field] && String(body[field]).length > max) {
    throw new Error(`Field too long: ${field} (max ${max} chars)`);
  }
}

return [{
  json: {
    resume_at:                    tomorrow.toISOString(),
    attendee_name:                body.attendee_name    || '',
    phone:                        body.phone            || '',
    email:                        body.email            || '',
    brought_you_in:               body.brought_you_in   || '',
    property_address:             body.property_address || '',
    property_notes:               body.property_notes   || '',
    listing_url:                  body.listing_url      || '',
    has_agent:                    body.has_agent === true || body.has_agent === 'true',
    representing_agent_name:      body.representing_agent_name      || '',
    representing_agent_brokerage: body.representing_agent_brokerage || '',
    agent_name:                   body.agent_name       || '',
    agent_email:                  body.agent_email      || '',
    agent_phone:                  body.agent_phone      || '',
    agent_company:                body.agent_company    || '',
  }
}];

const dedupeRow = $input.first().json;
const prev = $('Prep Wait Time').first().json;

if (dedupeRow.id) {
  // Lead exists — UPDATE
  return [{
    json: {
      ...prev,
      lead_query: `UPDATE leads SET
    phone = '${prev.phone.replace(/'/g, "''")}',
    metadata = metadata || jsonb_build_object(
      'property_address', '${prev.property_address.replace(/'/g, "''")}',
      'open_house_notes', '${prev.brought_you_in.replace(/'/g, "''")}'
    ),
    updated_at = NOW()
  WHERE id = '${dedupeRow.id}'`,
    }
  }];
} else {
  // New lead — INSERT
  const clientSubquery = `(SELECT id FROM clients WHERE primary_contact_email = '${prev.agent_email.replace(/'/g, "''")}' LIMIT 1)`;
  return [{
    json: {
      ...prev,
      lead_query: `INSERT INTO leads (client_id, lead_name, email, phone, source, metadata)
  VALUES (
    ${clientSubquery},
    '${prev.attendee_name.replace(/'/g, "''")}',
    '${prev.email.replace(/'/g, "''")}',
    '${prev.phone.replace(/'/g, "''")}',
    'open_house_web',
    jsonb_build_object(
      'property_address', '${prev.property_address.replace(/'/g, "''")}',
      'open_house_notes', '${prev.brought_you_in.replace(/'/g, "''")}'
    )
  )`,
    }
  }];
}

const response = $input.first().json;
const message = response.content[0].text.trim();

const prev = $('Prep Wait Time').first().json;

const sig = prev.agent_company
  ? '<p style="font-size:13px;color:#3A3F48;font-family:Arial,sans-serif;margin-top:8px;margin-bottom:0;">' + prev.agent_company + '</p>'
  : '';

const message_html = '<div style="font-family: Arial, sans-serif; font-size: 15px; line-height: 1.6; color: #222;">' +
  message.replace(/\n/g, '<br>') +
  sig +
  '</div>';

return [{
  json: {
    message,
    message_html,
    attendee_name:    prev.attendee_name,
    phone:            prev.phone,
    email:            prev.email,
    property_address: prev.property_address,
    property_notes:   prev.property_notes,
    agent_name:       prev.agent_name,
    agent_email:      prev.agent_email,
    agent_phone:      prev.agent_phone,
    agent_company:    prev.agent_company,
    has_email:        (prev.email || '').trim().length > 0,
  }
}];

