const p = $('Prep Wait Time').first().json;

const repName      = p.representing_agent_name      || 'Not provided';
const repBrokerage = p.representing_agent_brokerage || 'Not provided';
const attendeeEmail = p.email || 'Not provided';

const html = '<div style="font-family: Arial, sans-serif; font-size: 15px; line-height: 1.6; color: #222;">'
  + '<p>Hi ' + p.agent_name + ',</p>'
  + '<p>A buyer who is already working with an agent signed in at your open house at <strong>' + p.property_address + '</strong>. No follow-up email has been sent to this attendee.</p>'
  + '<table style="border-collapse:collapse; margin:8px 0;">'
  + '<tr><td colspan="2" style="padding-bottom:4px;"><strong>Attendee</strong></td></tr>'
  + '<tr><td style="padding:2px 12px 2px 0;color:#666;">Name</td><td>' + p.attendee_name + '</td></tr>'
  + '<tr><td style="padding:2px 12px 2px 0;color:#666;">Phone</td><td>' + p.phone + '</td></tr>'
  + '<tr><td style="padding:2px 12px 2px 0;color:#666;">Email</td><td>' + attendeeEmail + '</td></tr>'
  + '</table>'
  + '<table style="border-collapse:collapse; margin:8px 0;">'
  + '<tr><td colspan="2" style="padding-bottom:4px;"><strong>Their Agent</strong></td></tr>'
  + '<tr><td style="padding:2px 12px 2px 0;color:#666;">Name</td><td>' + repName + '</td></tr>'
  + '<tr><td style="padding:2px 12px 2px 0;color:#666;">Brokerage</td><td>' + repBrokerage + '</td></tr>'
  + '</table>'
  + '<p style="font-size:13px;color:#666;margin-top:16px;">You may want to reach out to their agent directly if you\'d like to discuss the property.<br>— Norr AI</p>'
  + '</div>';

return [{
  json: {
    agent_name:       p.agent_name,
    agent_email:      p.agent_email,
    property_address: p.property_address,
    subject:          'Represented buyer at your open house — ' + p.property_address,
    email_html:       html,
  }
}];
